import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Mail, Briefcase, PlusCircle, CheckCircle } from 'lucide-react';

const UserCard = ({ user }) => {
  const [isSent, setIsSent] = useState(false);

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      whileHover={{ y: -5 }}
      transition={{ duartion: 0.3 }}
      className="glass-card flex flex-col items-center group relative overflow-hidden"
    >
      <div className="absolute top-0 right-0 w-32 h-32 bg-primary-600/10 blur-3xl -z-10 group-hover:bg-primary-500/20 transition-all duration-300"></div>

      <div className="w-20 h-20 bg-gradient-to-br from-primary-400 to-primary-700 rounded-2xl mb-4 flex items-center justify-center shadow-lg transform rotate-3 group-hover:rotate-0 transition-all duration-300 relative">
        <span className="text-white text-3xl font-bold uppercase">{user.name[0]}</span>
        <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-green-500 border-4 border-background-dark rounded-full group-hover:scale-110 transition-transform"></div>
      </div>

      <h3 className="text-xl font-bold mb-1 group-hover:text-primary-400 transition-colors uppercase tracking-tight">{user.name}</h3>
      <div className="flex items-center text-sm text-gray-400 mb-4 font-medium italic opacity-70">
        <Briefcase size={14} className="mr-1" />
        {user.role}
      </div>

      <div className="flex flex-wrap gap-2 mb-6 justify-center">
        {user.skills.map(skill => (
          <span key={skill} className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-xs text-gray-400 hover:bg-white/10 hover:text-white transition-all">
            {skill}
          </span>
        ))}
      </div>

      <button 
        onClick={() => setIsSent(!isSent)}
        className={`w-full py-2.5 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all duration-300 ${
          isSent 
            ? 'bg-green-500/10 text-green-500 border border-green-500/30' 
            : 'bg-primary-600/20 text-primary-400 hover:bg-primary-600 hover:text-white border border-primary-600/30'
        }`}
      >
        {isSent ? (
          <>
            <CheckCircle size={18} />
            <span>Connection Sent</span>
          </>
        ) : (
          <>
            <PlusCircle size={18} />
            <span>Connect Buddy</span>
          </>
        )}
      </button>
    </motion.div>
  );
};

export default UserCard;
